svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var ns          = 'http://www.w3.org/2000/svg';
    var dataLayerEl = svgEl.querySelector('#data-layer');
    var dotsL       = svgEl.querySelector('#dots-layer');
    var hitLayer    = svgEl.querySelector('#hit-layer');
    var tipLayer    = svgEl.querySelector('#tip-layer');

    var series = [
      { id:1, cls:'series-1', label:'Cyan',
        vals:[38,42,46,50,55,60,66,72], ys:[342.4,311.7,294.1,268.1,261.2,221.8,205.0,165.6] },
      { id:2, cls:'series-2', label:'Violet',
        vals:[32,35,38,41,45,50,56,62], ys:[394.1,373.9,360.8,346.4,344.2,320.2,315.6,281.4] },
      { id:3, cls:'series-3', label:'Emerald',
        vals:[18,20,21,23,25,27,31,35], ys:[439.4,423.2,416.9,410.5,415.3,399.6,403.8,381.6] },
      { id:4, cls:'series-4', label:'Amber',
        vals:[11,12,13,14,15,17,19,22], ys:[468.3,459.3,457.1,457.1,455.5,444.2,453.9,437.7] },
      { id:5, cls:'series-5', label:'Slate',
        vals:[10,11,12,13,14,16,17,19], ys:[487.8,483.0,486.2,480.2,483.0,477.5,480.2,473.3] },
    ];

    var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
    var xs   = [68,180,291,403,515,627,738,850];
    var colW = 56;
    var allTips = {};

    var totals = xs.map(function(_,qi){
      return series.reduce(function(s,sr){ return s + sr.vals[qi]; }, 0);
    });

    function el(tag, attrs) {
      var e = document.createElementNS(ns, tag);
      Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
      return e;
    }

    xs.forEach(function(x, qi) {
      series.forEach(function(s) {
        var dot = el('circle', {
          cx:x, cy:s.ys[qi], r:4,
          'class':'col-dot ' + s.cls,
          style:'stroke:none', 'data-col':qi
        });
        dotsL.appendChild(dot);
      });
    });

    xs.forEach(function(x, qi) {
      var PAD = 14, DOT_R = 5, DOT_X = 16, LBL_X = 28, rx = 12;
      var rowH = 34, hdrH = 30, divH = 8, totH = 36;
      var TAIL = 14, tw = 10;
      var bh = hdrH + divH + series.length * rowH + divH + totH + PAD;

      var tipG = el('g', { 'class':'tip', id:'tip_'+qi });
      tipLayer.appendChild(tipG);
      allTips[qi] = tipG;

      var qLbl = el('text', { x:'0', y:'0',
        'text-anchor':'middle', 'dominant-baseline':'central', 'class':'tip-label' });
      qLbl.textContent = quarters[qi];
      tipG.appendChild(qLbl);

      var rowEls = [];
      series.forEach(function(s, si) {
        var dot  = el('circle', { cx:'0', cy:'0', r:DOT_R, 'class':s.cls, style:'stroke:none' });
        var sLbl = el('text', { x:'0', y:'0', 'dominant-baseline':'central', 'class':'tip-label' });
        sLbl.textContent = s.label;
        var sVal = el('text', { x:'0', y:'0', 'text-anchor':'end', 'dominant-baseline':'central',
          'class':'tip-value', 'font-size':'16' });
        sVal.textContent = '$'+s.vals[qi]+'M';
        tipG.appendChild(dot); tipG.appendChild(sLbl); tipG.appendChild(sVal);
        rowEls.push({ dot:dot, sLbl:sLbl, sVal:sVal });
      });

      var totLbl = el('text', { x:'0', y:'0', 'dominant-baseline':'central', 'class':'tip-label' });
      totLbl.textContent = 'Total';
      var totVal = el('text', { x:'0', y:'0', 'text-anchor':'end', 'dominant-baseline':'central', 'class':'tip-value' });
      totVal.textContent = '$'+totals[qi]+'M';
      tipG.appendChild(totLbl); tipG.appendChild(totVal);

      var maxLblW = 0;
      rowEls.forEach(function(r) { maxLblW = Math.max(maxLblW, LBL_X + r.sLbl.getBBox().width + 8); });
      maxLblW = Math.max(maxLblW, LBL_X + totLbl.getBBox().width + 8);
      var maxValW = 0;
      rowEls.forEach(function(r) { maxValW = Math.max(maxValW, r.sVal.getBBox().width); });
      maxValW = Math.max(maxValW, totVal.getBBox().width);
      var hw = Math.max((maxLblW + maxValW) / 2 + PAD, 160);
      var bw = hw * 2;

      var spaceR = 850 - x, spaceL = x - 68;
      var goRight = spaceR >= spaceL;
      var bL, bR;
      if (goRight) { bL = x + TAIL; bR = bL + bw; }
      else          { bR = x - TAIL; bL = bR - bw; }

      var bT = 302 - bh / 2, bB = bT + bh;
      if (bT < 100) { bT = 100; bB = bT + bh; }
      if (bB > 504) { bB = 504; bT = bB - bh; }
      var ancY = 302;
      var tY = Math.max(bT + rx + tw, Math.min(bB - rx - tw, ancY));

      qLbl.setAttribute('x', String(bL + hw));
      qLbl.setAttribute('y', String(bT + hdrH / 2));
      rowEls.forEach(function(r, si) {
        var rowY = bT + hdrH + divH + si * rowH + rowH / 2;
        r.dot.setAttribute('cx', String(bL + DOT_X));
        r.dot.setAttribute('cy', String(rowY));
        r.sLbl.setAttribute('x', String(bL + LBL_X));
        r.sLbl.setAttribute('y', String(rowY));
        r.sVal.setAttribute('x', String(bR - 8));
        r.sVal.setAttribute('y', String(rowY));
      });
      var totY = bT + hdrH + divH + series.length * rowH + divH + totH / 2;
      totLbl.setAttribute('x', String(bL + LBL_X));
      totLbl.setAttribute('y', String(totY));
      totVal.setAttribute('x', String(bR - 8));
      totVal.setAttribute('y', String(totY));

      var div1Y = bT + hdrH + divH / 2;
      var div2Y = bT + hdrH + divH + series.length * rowH + divH / 2;
      tipG.insertBefore(el('line', { x1:bL+8, y1:div1Y, x2:bR-8, y2:div1Y, 'class':'tip-divider' }), qLbl.nextSibling);
      tipG.appendChild(el('line',  { x1:bL+8, y1:div2Y, x2:bR-8, y2:div2Y, 'class':'tip-divider' }));

      tipG.insertBefore(el('rect', { x:bL, y:bT, width:bw, height:bh, rx:rx, 'class':'tip-bg' }), tipG.firstChild);

      var borderPath, tailPath;
      if (goRight) {
        borderPath = 'M'+bL+','+(tY-tw)
          +' L'+bL+','+(bT+rx)+' Q'+bL+','+bT+' '+(bL+rx)+','+bT
          +' L'+(bR-rx)+','+bT+' Q'+bR+','+bT+' '+bR+','+(bT+rx)
          +' L'+bR+','+(bB-rx)+' Q'+bR+','+bB+' '+(bR-rx)+','+bB
          +' L'+(bL+rx)+','+bB+' Q'+bL+','+bB+' '+bL+','+(bB-rx)
          +' L'+bL+','+(tY+tw);
        tailPath = 'M'+bL+','+(tY+tw)+' L'+x+','+ancY+' L'+bL+','+(tY-tw);
      } else {
        borderPath = 'M'+bR+','+(tY+tw)
          +' L'+bR+','+(bB-rx)+' Q'+bR+','+bB+' '+(bR-rx)+','+bB
          +' L'+(bL+rx)+','+bB+' Q'+bL+','+bB+' '+bL+','+(bB-rx)
          +' L'+bL+','+(bT+rx)+' Q'+bL+','+bT+' '+(bL+rx)+','+bT
          +' L'+(bR-rx)+','+bT+' Q'+bR+','+bT+' '+bR+','+(bT+rx)
          +' L'+bR+','+(tY-tw);
        tailPath = 'M'+bR+','+(tY-tw)+' L'+x+','+ancY+' L'+bR+','+(tY+tw);
      }
      tipG.insertBefore(el('path', { d:borderPath, 'class':'tip-border' }), tipG.children[1]);
      tipG.insertBefore(el('path', { d:tailPath,   'class':'tip-tail' }),   tipG.children[2]);

      var hx1 = Math.max(68,  x - colW);
      var hx2 = Math.min(850, x + colW);
      var hit = el('rect', { x:hx1, y:100, width:hx2-hx1, height:404,
        fill:'transparent', cursor:'crosshair', id:'hit'+qi });
      hitLayer.appendChild(hit);

      var ch = svgEl.querySelector('#ch' + qi);
      var colDots = dotsL.querySelectorAll('.col-dot[data-col="'+qi+'"]');

      hit.addEventListener('mouseenter', function() {
        dataLayerEl.classList.add('hovering');
        dotsL.querySelectorAll('.col-dot').forEach(function(d) { d.classList.remove('active'); });
        colDots.forEach(function(d) { d.classList.add('active'); });
        allTips[qi].style.opacity = '1';
        if (ch) ch.style.opacity = '1';
      });
      hit.addEventListener('mouseleave', function() {
        dataLayerEl.classList.remove('hovering');
        colDots.forEach(function(d) { d.classList.remove('active'); });
        allTips[qi].style.opacity = '';
        if (ch) ch.style.opacity = '';
      });
    });

    /* wave-edges are ordered we5,we4,we3,we2,we1 in markup — stagger bottom-to-top */
    var waveEls    = svgEl.querySelectorAll('.wave-edge');
    var waveDelays = [0, 0.25, 0.50, 0.75, 1.00];
    waveEls.forEach(function(el, i) {
      var delay = waveDelays[waveEls.length - 1 - i];
      el.style.animation = 'drawWave 1.2s cubic-bezier(0.4,0,0.2,1) ' + delay.toFixed(2) + 's';
      el.addEventListener('animationend', function() {
        el.style.animation = 'none';
        el.classList.add('visible');
      }, { once: true });
    });

    var areaEls = svgEl.querySelectorAll('.area-fill');
    var areaDelays = [0, 0.25, 0.50, 0.75, 1.00];
    areaEls.forEach(function(el, i) {
      el.style.animation = 'dataFadeIn 0.8s cubic-bezier(0.4,0,0.2,1) ' + areaDelays[areaEls.length - 1 - i] + 's';
      el.addEventListener('animationend', function() {
        el.style.animation = 'none';
        el.classList.add('visible');
      }, { once: true });
    });

    setTimeout(function() { dataLayerEl.classList.add('ready'); }, (1.00 + 0.8) * 1000 + 100);
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
